-    setuserfilter("R files (*.R)\0*.R\0S files (*.q, *.ssc, *.S)\0*.q;*.ssc;*.S\0All files (*.*)\0*.*\0\0");
+    setuserfilter( EDITORFILEFILTER);
      name = askfilesave(G_("Save script as"), current_name);
      if (name == NULL)
  	return;
@@ -337,7 +340,7 @@
